test_traj.command:
cat <<'EOF' > test_alive.ll
; Test for alive-tv verification

define i8 @test1(i16 %x) {
  %and = and i16 %x, 127
  %trunc = trunc i16 %and to i8
  ret i8 %trunc
}

define i8 @test2(i16 %x) {
  %and = and i16 %x, 255
  %trunc = trunc i16 %and to i8
  ret i8 %trunc
}

define i8 @test3(i16 %x) {
  %and = and i16 %x, 511
  %sub = sub i16 %and, 256
  %trunc = trunc i16 %sub to i8
  ret i8 %trunc
}
EOF

